{
 "level": "A2–B1",
 "intro": "In this topic you will learn <strong>Alternative Questions</strong> - questions that offer a choice between options using the conjunction <strong>or</strong>.",
 "rules": [
 {
 "label": "TWO OPTIONS",
 "color": "emerald",
 "text": "<strong>Choice between two</strong> — connect through or:",
 "example": "Do you prefer coffee or tea?"
 },
 {
 "label": "STRUCTURE",
 "color": "blue",
 "text": "<strong>As a Yes/No question</strong> + or + option:",
 "example": "Is it black or white?"
 },
 {
 "label": "ANSWER",
 "color": "amber",
 "text": "<strong>We choose option</strong>, we do not answer Yes/No:",
 "example": "Coffee, please. / I prefer tea."
 }
 ]
}

{
 "title": "1. What are alternative questions?",
 "intro": "Alternative questions are multiple-choice questions:",
 "items": [
 {
 "label": "Yes/No question",
 "title": "Do you like coffee?",
 "subtitle": "Answer: Yes/No"
 },
 {
 "label": "Alternative",
 "title": "Do you like coffee or tea?",
 "subtitle": "Answer: Coffee / Tea"
 },
 {
 "label": "Structure",
 "title": "Question + OR + Alternative",
 "subtitle": "Question + OR + Alternative"
 }
 ]
}

{
 "title": "2. Basic structure of alternative questions",
 "sections": [
 {
 "label": "With simple nouns",
 "color": "emerald",
 "description": "The simplest form is a choice between two nouns:",
 "examples": [
 {
 "en": "Do you prefer coffee or tea?",
 "ua": "Do you prefer coffee or tea?"
 },
 {
 "en": "Would you like meat or fish?",
 "ua": "Would you like meat or fish?"
 },
 {
 "en": "Is she a teacher or a doctor?",
 "ua": "Is she a teacher or a doctor?"
 },
 {
 "en": "Are you from Spain or Italy?",
 "ua": "Are you from Spain or Italy?"
 }
 ]
 },
 {
 "label": "With adjectives",
 "color": "sky",
 "description": "Alternative between adjectives - describing something:",
 "examples": [
 {
 "en": "Is it big or small?",
 "ua": "Is it big or small?"
 },
 {
 "en": "Is the test easy or difficult?",
 "ua": "Is the test easy or difficult?"
 },
 {
 "en": "Are you happy or sad?",
 "ua": "Are you happy or sad?"
 },
 {
 "en": "Was the movie good or bad?",
 "ua": "Was the movie good or bad?"
 }
 ]
 },
 {
 "label": "Structure",
 "color": "purple",
 "description": "General alternative question formula:",
 "examples": {
 "en": "Auxiliary + Subject + Verb + Option A + OR + Option B?",
 "ua": "Auxiliary + Subject + Verb + Option A + OR + Option B?"
 },
 "note": "📌 Structure as in Yes/No question, but added OR + alternative"
 }
 ]
}

{
 "title": "3. Alternative questions with DO/DOES/DID",
 "sections": [
 {
 "label": "Present Simple",
 "color": "emerald",
 "description": "In Present Simple we use <strong>do/does</strong> + or + alternative:",
 "examples": [
 {
 "en": "Do you walk or drive to work?",
 "ua": "Do you walk or drive to work?"
 },
 {
 "en": "Does she like cats or dogs?",
 "ua": "Does she like cats or dogs?"
 },
 {
 "en": "Do they live in a house or an apartment?",
 "ua": "Do they live in a house or an apartment?"
 }
 ]
 },
 {
 "label": "Past Simple",
 "color": "sky",
 "description": "In the Past Simple we use <strong>did</strong> + or + alternative:",
 "examples": [
 {
 "en": "Did you go by bus or by train?",
 "ua": "Did you go by bus or by train?"
 },
 {
 "en": "Did she buy a laptop or a tablet?",
 "ua": "Did she buy a laptop or a tablet?"
 },
 {
 "en": "Did they win or lose?",
 "ua": "Did they win or lose?"
 }
 ]
 },
 {
 "label": "With different verbs",
 "color": "amber",
 "description": "You can ask questions about different actions:",
 "examples": [
 {
 "en": "Do you want to stay or leave?",
 "ua": "Do you want to stay or leave?"
 },
 {
 "en": "Did you call or text him?",
 "ua": "Did you call or text him?"
 },
 {
 "en": "Does he work or study? verbs, nouns, adjectives",
 "ua": "Does he work or study? verbs, nouns, adjectives"
 }
 ],
 "note": "Use the pattern in the examples and focus on the highlighted words."
 }
 ]
}

{
 "title": "4. Alternative questions with TO BE",
 "sections": [
 {
 "label": "Present — AM/IS/ARE",
 "color": "blue",
 "description": "With the verb <strong>to be</strong> we make inversion + or:",
 "examples": [
 {
 "en": "Are you a student or a teacher?",
 "ua": "Are you a student or a teacher?"
 },
 {
 "en": "Is it hot or cold outside?",
 "ua": "Is it hot or cold outside?"
 },
 {
 "en": "Are they British or American?",
 "ua": "Are they British or American?"
 }
 ]
 },
 {
 "label": "Past — WAS/WERE",
 "color": "purple",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "Was the book interesting or boring?",
 "ua": "Was the book interesting or boring?"
 },
 {
 "en": "Were you at home or at work?",
 "ua": "Were you at home or at work?"
 },
 {
 "en": "Was she happy or upset?",
 "ua": "Was she happy or upset?"
 }
 ]
 },
 {
 "label": "With the pronouns THIS/THAT",
 "color": "rose",
 "description": "Alternative when identifying objects:",
 "examples": [
 {
 "en": "Is this your bag or hers?",
 "ua": "Is this your bag or hers?"
 },
 {
 "en": "Is that a cat or a Dog? Alternative questions with modal verbs",
 "ua": "Is that a cat or a Dog? Alternative questions with modal verbs"
 },
 {
 "en": "Are these apples or pears?",
 "ua": "Are these apples or pears?"
 }
 ],
 "note": "Use the pattern in the examples and focus on the highlighted words."
 }
 ]
}

{
 "title": "5. Alternative questions with modal verbs",
 "sections": [
 {
 "label": "CAN / COULD",
 "color": "emerald",
 "description": "With <strong>can/could</strong> to select possibilities or abilities:",
 "examples": [
 {
 "en": "Can you swim or dive?",
 "ua": "Can you swim or dive?"
 },
 {
 "en": "Could we meet today or tomorrow?? desire:",
 "ua": "Could we meet today or tomorrow?? desire:"
 },
 {
 "en": "Can she speak French or German?",
 "ua": "Can she speak French or German?"
 }
 ]
 },
 {
 "label": "WILL / WOULD",
 "color": "sky",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "Will you come by car or by bus?",
 "ua": "Will you come by car or by bus?"
 },
 {
 "en": "Would you like wine or beer?",
 "ua": "Would you like wine or beer?"
 },
 {
 "en": "Will they arrive in the morning or evening?",
 "ua": "Will they arrive in the morning or evening?"
 }
 ]
 },
 {
 "label": "SHOULD / MUST",
 "color": "amber",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "Should I call or text you?",
 "ua": "Should I call or text you?"
 },
 {
 "en": "Must we pay by cash or card?",
 "ua": "Must we pay by cash or card?"
 }
 ],
 "note": "📌 Modal verb + subject + verb + or + alternative"
 }
 ]
}

{
 "title": "6. More complex alternative questions",
 "sections": [
 {
 "label": "With phrases and sentences",
 "color": "purple",
 "description": "OR can connect whole phrases or sentences:",
 "examples": [
 {
 "en": "Do you want to go now or wait a bit?",
 "ua": "Do you want to go now or wait a bit?"
 },
 {
 "en": "Should we eat at home or go to a restaurant?",
 "ua": "Should we eat at home or go to a restaurant?"
 },
 {
 "en": "Will you study English or learn another language?",
 "ua": "Will you study English or learn another language?"
 }
 ]
 },
 {
 "label": "More than two options",
 "color": "blue",
 "description": "More than two options can be offered:",
 "examples": [
 {
 "en": "Do you prefer red, blue, or green?",
 "ua": "Do you prefer red, blue, or green?"
 },
 {
 "en": "Should we meet on Monday, Tuesday, or Wednesday?",
 "ua": "Should we meet on Monday, Tuesday, or Wednesday?"
 },
 {
 "en": "Is she from France, Spain, or Italy?",
 "ua": "Is she from France, Spain, or Italy?"
 }
 ]
 },
 {
 "label": "With question words",
 "color": "rose",
 "description": "Alternative questions can start with Wh-words:",
 "examples": [
 {
 "en": "Which do you prefer — coffee or tea? tea?",
 "ua": "Which do you prefer — coffee or tea? tea?"
 },
 {
 "en": "Where should we go — to the park or to the beach?",
 "ua": "Where should we go — to the park or to the beach?"
 },
 {
 "en": "When will you come — today or tomorrow?",
 "ua": "When will you come — today or tomorrow?"
 }
 ],
 "note": "📌 Which is often used to choose between options"
 }
 ]
}

{
 "title": "7. How to answer alternative questions",
 "sections": [
 {
 "label": "Choose an option",
 "color": "emerald",
 "description": "The answer is one of the proposed options, NOT Yes/No:",
 "examples": [
 {
 "en": "Q: Coffee or tea? — A: Coffee, please.",
 "ua": "Q: Coffee or tea? — A: Coffee, please."
 },
 {
 "en": "Q: Is it black or white? — A: It's black.",
 "ua": "Q: Is it black or white? — A: It's black."
 },
 {
 "en": "Q: Do you walk or drive? — A: I usually drive.",
 "ua": "Q: Do you walk or drive? — A: I usually drive."
 }
 ]
 },
 {
 "label": "Reject both",
 "color": "sky",
 "description": "You can reject both options and offer a third:",
 "examples": [
 {
 "en": "Q: Coffee or tea? — A: Neither. Water, please.",
 "ua": "Q: Coffee or tea? — A: Neither. Water, please."
 },
 {
 "en": "Q: Are you from Spain or Italy? — A: Neither. I'm from France.",
 "ua": "Q: Are you from Spain or Italy? — A: Neither. I'm from France."
 }
 ]
 },
 {
 "label": "Choose both",
 "color": "amber",
 "description": "Sometimes you can choose both:",
 "examples": [
 {
 "en": "Q: Do you like cats or dogs? — A: Both! I love animals.",
 "ua": "Q: Do you like cats or dogs? — A: Both! I love animals."
 },
 {
 "en": "Q: Coffee or tea? — A: I like both.",
 "ua": "Q: Coffee or tea? — A: I like both."
 }
 ],
 "note": "📌 Neither — neither, Both — both"
 }
 ]
}

{
 "title": "8. Comparison of Yes/No and Alternative Questions",
 "intro": "Main differences between the two question types:",
 "rows": [
 {
 "en": "Yes/No Question",
 "ua": "Yes/No Question",
 "note": "Do you like coffee? → Yes/No"
 },
 {
 "en": "Alternative Question",
 "ua": "Alternative Question",
 "note": "Do you like coffee or tea? → Coffee/Tea"
 },
 {
 "en": "Structure",
 "ua": "Structure",
 "note": "Aux + Subject + Verb + OR + Alternative"
 },
 {
 "en": "Answer type",
 "ua": "Answer type",
 "note": "Choose one option, NOT Yes/No"
 },
 {
 "en": "Intonation",
 "ua": "Intonation",
 "note": "Falls on the last option"
 }
 ],
 "warning": "📌 Main difference: <strong>OR + alternative</strong>"
}

{
 "title": "9. Typical errors",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Yes/No answer instead of choosing an option.",
 "wrong": "❌ Q: Coffee or tea? A: Yes.",
 "right": "​​​​ <span class=\"font-mono\">Q: Coffee or tea? A: Coffee, please.</span>"
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Wrong order of words in the question.",
 "wrong": "❌ You prefer coffee or tea?",
 "right": " ✅ <span class=\"font-mono\">Do you prefer coffee or tea?</span>"
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "Forget the OR between options.",
 "wrong": "❌ Do you want coffee, tea?",
 "right": "​​​​​​​​ auxiliary."
 },
 {
 "label": "Mistake 4",
 "color": "purple",
 "title": "Using the wrong verb form after an auxiliary.",
 "wrong": "❌ Does she like cats or dogs?",
 "right": "​​​​ <span class=\"font-mono\">Does she like cats or dogs?</span>"
 }
 ]
}

{
 "title": "11. Practice",
 "select_title": "Exercise 1. Choose the correct option",
 "select_intro": "Choose the correct form of the alternative question.",
 "selects": [
 {
 "label": "a) You prefer coffee or tea? / b) Do you prefer coffee or tea? / c) Do you prefer coffee and tea?",
 "prompt": "Which option is correct?"
 },
 {
 "label": "a) Is it hot or cold? / b) Is it hot or cold? / c) Does it hot or cold?",
 "prompt": "Which option is correct?"
 },
 {
 "label": "a) Can you swim and dive? / b) Can you swim or dive? / c) Can you swim or dive? options.",
 "prompt": "Which option is correct?"
 }
 ],
 "options": [
 "a",
 "b",
 "c"
 ],
 "input_title": "Exercise 2. Make an alternative question",
 "input_intro": "Make an alternative question from the options.",
 "inputs": [
 {
 "before": "She likes (cats / dogs). → ",
 "after": ""
 },
 {
 "before": "You are from (Spain / Italy). → ",
 "after": ""
 },
 {
 "before": "They will come (today / tomorrow). → ",
 "after": ""
 },
 {
 "before": "It is (big / small). →",
 "after": ""
 }
 ],
 "rephrase_title": "Exercise 3. Correct the error",
 "rephrase_intro": "Find and correct the error in the alternative question.",
 "rephrase": [
 {
 "example_label": "Example:",
 "example_original": "You prefer coffee or tea?",
 "example_target": "Do you prefer coffee or tea?"
 },
 {
 "original": "1. Does she like cats or dogs?",
 "placeholder": "Fix the error"
 },
 {
 "original": "2. Is it hot cold?",
 "placeholder": "Fix the error"
 },
 {
 "original": "3. You can swim or dive?",
 "placeholder": "Correct a mistake"
 }
 ]
}

